// ── FIXED: flatten webhook body once, enrich with weather ──
const raw = $('New Appointment Booking').first().json;
// n8n webhook sends body fields under .body in responseNode mode
const apt = raw.body ?? raw;
const wx  = $input.first().json;

// Open-Meteo weathercode → label mapping (subset)
const WMO = {0:'Clear',1:'Clear',2:'Cloudy',3:'Cloudy',45:'Cloudy',48:'Cloudy',
  51:'Rainy',53:'Rainy',55:'Rainy',61:'Rainy',63:'Rainy',65:'Rainy',
  71:'Cold',73:'Cold',75:'Cold',80:'Rainy',81:'Rainy',82:'Rainy',
  95:'Rainy',96:'Rainy',99:'Rainy'};

const code  = wx?.current?.weathercode ?? 0;
const tempC = wx?.current?.temperature_2m ?? 20;
let weather = WMO[code] ?? 'Clear';
if (tempC > 36) weather = 'Hot';
else if (tempC < 8 && weather === 'Clear') weather = 'Cold';

const aptDate    = new Date(apt.appointment_date);
const bookedDate = new Date(apt.booked_date || new Date().toISOString());
const leadDays   = Math.max(0, Math.round((aptDate - bookedDate) / 86400000));
const dow        = aptDate.getDay();
const dayOfWeek  = dow === 0 ? 6 : dow - 1;   // Mon=0 … Sun=6

return [{ json: { ...apt, weather, temperature_c: tempC, lead_days: leadDays, day_of_week: dayOfWeek } }];

// ── Doctome No-Show Scoring Engine v1.1 ──
const MODEL = {
  base_rate: 0.4133,
  features: {
    distance:       { near:{woe:-0.2705}, mid:{woe:0.2295}, far:{woe:0.5124} },
    lead_days:      { short:{woe:-0.2022}, medium:{woe:0.0649}, long:{woe:0.1831} },
    weather:        { Clear:{woe:-0.0336}, Cloudy:{woe:-0.0108}, Rainy:{woe:0.0288},
                      Hot:{woe:0.1053}, Sandstorm:{woe:0.2453}, Cold:{woe:-0.3322} },
    prior_no_shows: { "0":{woe:-0.150}, "1":{woe:0.400}, "2+":{woe:0.850} },
    age_group:      { child:{woe:-0.0431}, adult:{woe:-0.0341}, senior:{woe:0.2039} },
    day_of_week:    { "0":{woe:0.0843},"1":{woe:-0.1576},"2":{woe:-0.0620},
                      "3":{woe:0.0380},"4":{woe:0.2747},"5":{woe:0.2577},"6":{woe:-0.3970} },
    hour:           { early:{woe:0.2613}, core:{woe:-0.0059}, late:{woe:-0.0772} },
    payment:        { Cash:{woe:0.0534}, Insurance:{woe:-0.0079}, Corporate:{woe:-0.0475} },
    first_visit:    { "0":{woe:-0.04}, "1":{woe:0.10} },
    reminder:       { "true":{woe:-0.2113}, "false":{woe:0.1622} }
  },
  thresholds: { high: 0.60, medium: 0.40 },
  weights: { prior_no_shows:0.28, distance:0.18, lead_days:0.15, weather:0.10,
             reminder:0.10, age_group:0.07, day_of_week:0.05, hour:0.04,
             payment:0.02, first_visit:0.01 }
};
function dist(km)  { return km>40?'far':km>15?'mid':'near'; }
function lead(d)   { return d>14?'long':d>7?'medium':'short'; }
function age(a)    { return a<18?'child':a>70?'senior':'adult'; }
function hour_(h)  { return h<9?'early':h>16?'late':'core'; }
function woe(map,k,fb){ return (map[k]??map[fb??k]??{woe:0}).woe; }

const i   = $input.first().json;
const prK = Number(i.prior_no_shows)>=2?'2+':String(Math.min(1,Number(i.prior_no_shows)||0));
const rem = String(i.reminder_sent===true||i.reminder_sent==='true'||i.reminder_sent===1);
const F=MODEL.features, W=MODEL.weights;
const wSum =
  W.prior_no_shows * woe(F.prior_no_shows, prK) +
  W.distance       * woe(F.distance,       dist(Number(i.distance_km)||5)) +
  W.lead_days      * woe(F.lead_days,      lead(Number(i.lead_days)||3)) +
  W.weather        * woe(F.weather,        i.weather||'Clear','Clear') +
  W.reminder       * woe(F.reminder,       rem) +
  W.age_group      * woe(F.age_group,      age(Number(i.age)||30)) +
  W.day_of_week    * woe(F.day_of_week,    String(Number(i.day_of_week)||0)) +
  W.hour           * woe(F.hour,           hour_(Number(i.appointment_hour)||10)) +
  W.payment        * woe(F.payment,        i.payment_type||'Cash','Cash') +
  W.first_visit    * woe(F.first_visit,    String(Number(i.is_first_visit)||0));

const base = MODEL.base_rate;
const prob = Math.round((1/(1+Math.exp(-(Math.log(base/(1-base))+wSum*3.5))))*100)/100;
const risk = prob>=MODEL.thresholds.high?'HIGH':prob>=MODEL.thresholds.medium?'MEDIUM':'LOW';
const emoji= risk==='HIGH'?'🔴':risk==='MEDIUM'?'🟡':'🟢';
const action=risk==='HIGH'?'Send reminder NOW + flag for overbooking':
             risk==='MEDIUM'?'Schedule reminder 24h before appointment':'No action needed';

const drivers=[
  {f:'Prior no-shows', s:W.prior_no_shows*Math.abs(woe(F.prior_no_shows,prK)), r:woe(F.prior_no_shows,prK)},
  {f:'Distance',       s:W.distance*Math.abs(woe(F.distance,dist(Number(i.distance_km)||5))), r:woe(F.distance,dist(Number(i.distance_km)||5))},
  {f:'Lead time',      s:W.lead_days*Math.abs(woe(F.lead_days,lead(Number(i.lead_days)||3))), r:woe(F.lead_days,lead(Number(i.lead_days)||3))},
  {f:'Weather',        s:W.weather*Math.abs(woe(F.weather,i.weather||'Clear','Clear')), r:woe(F.weather,i.weather||'Clear','Clear')},
  {f:'No reminder',    s:W.reminder*Math.abs(woe(F.reminder,rem)), r:woe(F.reminder,rem)},
].filter(d=>d.r>0.05).sort((a,b)=>b.s-a.s).slice(0,3).map(d=>d.f);

return [{json:{
  appointment_id:i.appointment_id, patient_id:i.patient_id,
  patient_name:i.patient_name||'Patient', patient_phone:i.patient_phone||null,
  appointment_date:i.appointment_date, appointment_hour:Number(i.appointment_hour)||10,
  specialty:i.specialty||'General Practice', clinic_name:i.clinic_name||'Doctome Clinic',
  wilaya:i.wilaya||'', age:Number(i.age)||30, distance_km:Number(i.distance_km)||5,
  gender:i.gender||'', prior_visits:i.prior_visits||0, booked_date:i.booked_date||'',
  prior_no_shows:Number(i.prior_no_shows)||0, is_first_visit:Number(i.is_first_visit)||0,
  payment_type:i.payment_type||'Cash', reminder_sent:rem==='true',
  no_show_probability:prob, risk_level:risk, risk_emoji:emoji, action, top_risk_drivers:drivers,
  scored_at:new Date().toISOString(), weather:i.weather||'Clear',
  lead_days:Number(i.lead_days)||3, day_of_week:Number(i.day_of_week)||0
}}];

const appointments=$input.all().map(i=>i.json);
const BASE=0.4133,T={high:0.60,medium:0.40};
const W2={prior_no_shows:0.28,distance:0.18,lead_days:0.15,weather:0.10,reminder:0.10,age_group:0.07};
const RW={prior_no_shows:{'0':-0.150,'1':0.400,'2+':0.850},
  distance:{near:-0.2705,mid:0.2295,far:0.5124},
  lead_days:{short:-0.2022,medium:0.0649,long:0.1831},
  weather:{Clear:-0.0336,Cloudy:-0.0108,Rainy:0.0288,Hot:0.1053,Sandstorm:0.2453,Cold:-0.3322},
  reminder:{'true':-0.2113,'false':0.1622},
  age_group:{child:-0.0431,adult:-0.0341,senior:0.2039}};
function sig(x){return 1/(1+Math.exp(-x));}
const today=new Date().toISOString().split('T')[0];
const results=appointments.map(apt=>{
  const prK=Number(apt.prior_no_shows)>=2?'2+':String(Math.min(1,Number(apt.prior_no_shows)||0));
  const rem=String(apt.reminder_sent===true||apt.reminder_sent==='true'||apt.reminder_sent===1);
  const distB=Number(apt.distance_km)>40?'far':Number(apt.distance_km)>15?'mid':'near';
  let ld=Number(apt.lead_days)||0;
  if(!ld&&apt.booked_date&&apt.appointment_date)
    ld=Math.max(0,Math.round((new Date(apt.appointment_date)-new Date(apt.booked_date))/86400000));
  const leadB=ld>14?'long':ld>7?'medium':'short';
  const ageB=Number(apt.age)<18?'child':Number(apt.age)>70?'senior':'adult';
  const wx=apt.weather||'Clear';
  const wSum=W2.prior_no_shows*(RW.prior_no_shows[prK]??0)+W2.distance*(RW.distance[distB]??0)+
    W2.lead_days*(RW.lead_days[leadB]??0)+W2.weather*(RW.weather[wx]??0)+
    W2.reminder*(RW.reminder[rem]??0)+W2.age_group*(RW.age_group[ageB]??0);
  const prob=Math.round(sig(Math.log(BASE/(1-BASE))+wSum*3.5)*100)/100;
  const risk=prob>=T.high?'HIGH':prob>=T.medium?'MEDIUM':'LOW';
  return {...apt,no_show_probability:prob,risk_level:risk,scored_at:new Date().toISOString()};
});
const high=results.filter(r=>r.risk_level==='HIGH').length;
const med=results.filter(r=>r.risk_level==='MEDIUM').length;
const low=results.filter(r=>r.risk_level==='LOW').length;
return [...results.map(r=>({json:r})),
  {json:{_summary:true,total:results.length,high,medium:med,low,date:today}}];

// ── JWT Middleware ──
// Secret stored as n8n env var: JWT_SECRET
// Header: Authorization: Bearer <token>
const crypto = require('crypto');

const SECRET = $vars.JWT_SECRET || 'CHANGE_ME_IN_N8N_ENV';
const req = $input.first().json;
const authHeader = req.headers?.authorization || req.headers?.Authorization || '';
const token = authHeader.startsWith('Bearer ') ? authHeader.slice(7) : null;

if (!token) {
  return [{ json: { _authError: true, status: 401, message: 'Missing Authorization header' } }];
}

try {
  // Manual HS256 JWT verification (no external library needed)
  const parts = token.split('.');
  if (parts.length !== 3) throw new Error('Malformed token');

  const [headerB64, payloadB64, sigB64] = parts;

  // Verify signature
  const signingInput = `${headerB64}.${payloadB64}`;
  const expectedSig = crypto
    .createHmac('sha256', SECRET)
    .update(signingInput)
    .digest('base64url');

  if (expectedSig !== sigB64) throw new Error('Invalid signature');

  // Decode payload
  const payload = JSON.parse(Buffer.from(payloadB64, 'base64url').toString('utf8'));

  // Check expiry
  if (payload.exp && Date.now() / 1000 > payload.exp) throw new Error('Token expired');

  // Attach user context to request, pass through
  return [{ json: { ...req, _auth: { userId: payload.sub, role: payload.role, exp: payload.exp } } }];
} catch (err) {
  return [{ json: { _authError: true, status: 401, message: err.message } }];
}

// ── Send confirmation to tomorrow's appointments via SSE/in-app ──
// Filters only appointments for TOMORROW from the sheet data
const tomorrow = new Date(Date.now() + 86400000).toISOString().split('T')[0];
const appts = $input.all().map(i => i.json).filter(a => !a._summary && a.appointment_date === tomorrow);

return appts.map(a => ({ json: {
  appointment_id: a.appointment_id,
  patient_id:     a.patient_id,
  patient_name:   a.patient_name  || 'Patient',
  patient_phone:  a.patient_phone || null,
  doctor_id:      a.doctor_id     || null,
  specialty:      a.specialty     || 'General Practice',
  appointment_date: a.appointment_date,
  appointment_hour: a.appointment_hour || 10,
  risk_level:     a.risk_level    || 'LOW',
  confirm_url:    `https://YOUR_N8N_HOST/webhook/confirm-attendance?apt=${a.appointment_id}&r=yes`,
  decline_url:    `https://YOUR_N8N_HOST/webhook/confirm-attendance?apt=${a.appointment_id}&r=no`,
  message: `🏥 Doctome – Appointment Tomorrow\n\nHello ${a.patient_name || 'Patient'}, you have an appointment TOMORROW (${a.appointment_date}) at ${a.appointment_hour || 10}:00 (${a.specialty || ''}).\n\nWill you attend?\n✅ YES: https://YOUR_N8N_HOST/webhook/confirm-attendance?apt=${a.appointment_id}&r=yes\n❌ NO: https://YOUR_N8N_HOST/webhook/confirm-attendance?apt=${a.appointment_id}&r=no`
}}));

// Build Twilio WhatsApp message per appointment
const a = $input.first().json;
if (!a.patient_phone) return []; // skip if no phone
return [{ json: a }];

// ── Build in-app notification for patient to confirm/decline ──
// Instead of WhatsApp, we write to MongoDB notifications so the frontend
// can poll/SSE and show the patient a YES/NO prompt in their dashboard.
const a = $input.first().json;
if (!a.appointment_id) return [];
const BASE = 'https://YOUR_N8N_HOST/webhook';
return [{ json: {
  user_id:          a.patient_id,          // patient's user_id for SSE lookup
  type:             'confirmation_request',
  appointment_id:   a.appointment_id,
  patient_name:     a.patient_name || 'Patient',
  specialty:        a.specialty || '',
  appointment_date: a.appointment_date,
  appointment_hour: a.appointment_hour || 10,
  risk_level:       a.risk_level || 'LOW',
  confirm_url:      `${BASE}/confirm-attendance?apt=${a.appointment_id}&r=yes`,
  decline_url:      `${BASE}/confirm-attendance?apt=${a.appointment_id}&r=no`,
  message:          `📅 Please confirm your appointment on ${a.appointment_date} at ${a.appointment_hour || 10}:00 (${a.specialty || ''}).`,
  sent_at:          new Date().toISOString(),
  timestamp:        new Date().toISOString()
} }];

// ── Handle patient confirmation response ──
// Called when patient clicks YES or NO link
const q = $input.first().json.query ?? {};
const aptId    = q.apt  || q.appointment_id;
const response = (q.r   || q.response || '').toLowerCase();   // 'yes' or 'no'

if (!aptId || !['yes','no'].includes(response)) {
  return [{ json: { _error: true, message: 'Invalid confirmation link' } }];
}

return [{ json: {
  appointment_id: aptId,
  confirmed:      response === 'yes',
  declined:       response === 'no',
  responded_at:   new Date().toISOString(),
  response
} }];

const conf = $('Parse Confirmation').first().json;
const apt  = $input.first().json;
return [{ json: { ...apt, ...conf } }];

// ── Notify doctor when patient declines ──
// Look up the appointment → find doctor → store SSE notification for doctor's user_id
const d = $input.first().json;
// We store a notification for the doctor to be picked up via SSE
return [{ json: {
  user_id:       d.doctor_user_id || d.doctor_id || 'doctor',
  type:          'patient_declined',
  appointment_id: d.appointment_id,
  patient_name:  d.patient_name || 'Patient',
  specialty:     d.specialty    || '',
  appointment_date: d.appointment_date,
  appointment_hour: d.appointment_hour,
  message:       `❌ Patient ${d.patient_name || 'Patient'} declined their appointment on ${d.appointment_date} at ${d.appointment_hour}:00 (${d.specialty || ''})`,
  timestamp:     new Date().toISOString()
} }];

// ── Find HIGH-risk appointments ~2 hours from now ──
// Runs every 30 min. Checks appointments where:
//   - appointment_date = today
//   - appointment_hour is 2h ahead (within ±15 min window)
//   - risk_level = HIGH
//   - reminder_2h_sent != true  (idempotency guard)
const now    = new Date();
const target = new Date(now.getTime() + 2 * 60 * 60 * 1000);   // 2h from now
const today  = now.toISOString().split('T')[0];
const targetHour = target.getHours();  // e.g. if it's 08:00, target = 10

return [{ json: {
  _query: JSON.stringify({
    appointment_date: today,
    appointment_hour: targetHour,
    risk_level: 'HIGH',
    reminder_2h_sent: { $ne: true }
  })
} }];

// ── Send 2h reminder WhatsApp message ──
const a = $input.first().json;
if (!a.patient_phone) return [];
const msg = `⏰ Doctome Reminder\n\nHi ${a.patient_name || 'Patient'}, your appointment is in approximately 2 hours (${a.appointment_hour}:00, ${a.specialty || ''}).\n\nPlease make sure you're on your way. We look forward to seeing you! 🏥`;
return [{ json: { ...a, _reminderMessage: msg } }];

// ── Build in-app 2h reminder notification for patient ──
const a = $input.first().json;
if (!a.patient_id) return [];
return [{ json: {
  user_id:          a.patient_id,
  type:             'reminder_2h',
  appointment_id:   a.appointment_id,
  patient_name:     a.patient_name || 'Patient',
  specialty:        a.specialty || '',
  appointment_date: a.appointment_date,
  appointment_hour: a.appointment_hour || 10,
  message:          `⏰ Reminder: your appointment is in ~2 hours at ${a.appointment_hour || 10}:00 (${a.specialty || ''}). Please head over soon! 🏥`,
  timestamp:        new Date().toISOString()
} }];

// Mark reminder as sent to prevent duplicate sends
const a = $input.first().json;
return [{ json: {
  _filter: JSON.stringify({ appointment_id: a.appointment_id }),
  appointment_id: a.appointment_id,
  patient_name: a.patient_name
} }];

// ── Find HIGH-risk patients with future appointments to offer freed slot ──
// Triggered after a patient declines. d = declined appointment details.
const d = $input.first().json;
const today = new Date().toISOString().split('T')[0];
// Build query: future appointments that are HIGH risk, not yet confirmed, different appointment
const query = JSON.stringify({
  appointment_date: { $gte: today },
  risk_level:       'HIGH',
  appointment_id:   { $ne: d.appointment_id },
  patient_confirmed: { $ne: true },
  patient_declined:  { $ne: true },
  reschedule_offer_sent: { $ne: true }
});
return [{ json: {
  _freed_appointment_id:   d.appointment_id,
  _freed_appointment_date: d.appointment_date,
  _freed_appointment_hour: d.appointment_hour || 10,
  _freed_specialty:        d.specialty || '',
  _freed_doctor_id:        d.doctor_id || d.doctor_user_id || 'unknown',
  _query: query
} }];

// ── Build reschedule offer record and per-patient notifications ──
// We emit TWO types of items:
//   1. One offer record (type=_offer) to store in reschedule_offers collection
//   2. One notification per patient to store in notifications collection
const patients = $input.all().map(i => i.json);
if (!patients.length) return [{ json: { _noPatients: true } }];

// Grab freed slot info from the first item's context carried via Code node above
// (n8n re-attaches using $('Find HIGH-Risk Patients for Reschedule').first())
const ctx = $('Find HIGH-Risk Patients for Reschedule').first().json;
const offerId = `offer_${ctx._freed_appointment_id}_${Date.now()}`;
const BASE     = 'https://YOUR_N8N_HOST/webhook';
const patientIds = patients.map(p => p.patient_id);

// ── 1 offer record ──
const offerRecord = {
  _item_type:           '_offer',
  offer_id:             offerId,
  slot_appointment_id:  ctx._freed_appointment_id,
  slot_date:            ctx._freed_appointment_date,
  slot_hour:            ctx._freed_appointment_hour,
  slot_specialty:       ctx._freed_specialty,
  doctor_id:            ctx._freed_doctor_id,
  offered_to:           patientIds,
  status:               'pending',
  accepted_by:          null,
  created_at:           new Date().toISOString()
};

// ── 1 notification per patient ──
const notifications = patients.map(p => ({
  _item_type:       '_notification',
  offer_id:         offerId,
  user_id:          p.patient_id,
  type:             'reschedule_offer',
  appointment_id:   p.appointment_id,   // patient's OWN appointment
  slot_appointment_id: ctx._freed_appointment_id,
  message:          `📢 A slot just opened up!\n${ctx._freed_specialty || 'Medical'} appointment on ${ctx._freed_appointment_date} at ${ctx._freed_appointment_hour || '?'}:00.\nWant to reschedule your appointment to this slot?\n✅ YES: ${BASE}/reschedule-accept?offer=${offerId}&patient=${p.patient_id}&r=yes\n❌ NO: ${BASE}/reschedule-accept?offer=${offerId}&patient=${p.patient_id}&r=no`,
  accept_url:       `${BASE}/reschedule-accept?offer=${offerId}&patient=${p.patient_id}&r=yes`,
  decline_url:      `${BASE}/reschedule-accept?offer=${offerId}&patient=${p.patient_id}&r=no`,
  timestamp:        new Date().toISOString()
}));

return [offerRecord, ...notifications].map(j => ({ json: j }));

// ── Parse reschedule accept/decline response ──
const q = $input.first().json.query ?? {};
const offerId   = q.offer   || null;
const patientId = q.patient || null;
const response  = (q.r || '').toLowerCase(); // 'yes' or 'no'

if (!offerId || !patientId || !['yes','no'].includes(response)) {
  return [{ json: { _error: true, message: 'Invalid reschedule link' } }];
}
return [{ json: {
  offer_id:   offerId,
  patient_id: patientId,
  accepted:   response === 'yes',
  declined:   response === 'no',
  responded_at: new Date().toISOString()
} }];

const resp  = $('Parse Reschedule Response').first().json;
const offer = $input.first().json;
return [{ json: { ...offer, ...resp } }];

// ── Process accepted reschedule ──
// 1. Mark offer as accepted
// 2. Swap appointment_id for the accepting patient  
// 3. Create notifications telling other patients the slot is gone
const d = $input.first().json;
return [{ json: {
  // Data for the offer update
  offer_id:           d.offer_id,
  accepted_by:        d.patient_id,
  status:             'accepted',
  accepted_at:        new Date().toISOString(),
  slot_appointment_id: d.slot_appointment_id,
  slot_date:          d.slot_date,
  slot_hour:          d.slot_hour,
  slot_specialty:     d.slot_specialty,
  patient_id:         d.patient_id,
  offered_to:         d.offered_to || []
} }];

// ── Notify other patients that the slot has been taken ──
// For each patient in offered_to (except the one who accepted), 
// insert a notification that the slot is no longer available.
const d = $input.first().json;
const others = (d.offered_to || []).filter(pid => pid !== d.accepted_by);
if (!others.length) return [{ json: { _noOthers: true } }];

return others.map(pid => ({ json: {
  user_id:    pid,
  type:       'reschedule_slot_taken',
  offer_id:   d.offer_id,
  message:    `ℹ️ The slot on ${d.slot_date} at ${d.slot_hour || '?'}:00 (${d.slot_specialty || ''}) has been taken by another patient.`,
  timestamp:  new Date().toISOString()
} }));

// Tag each high-risk patient's appointment so we don't spam them
const n = $input.first().json;
if (n._item_type !== '_notification' || n._noPatients) return [];
return [{ json: {
  appointment_id: n.appointment_id,
  reschedule_offer_sent: true,
  reschedule_offer_sent_at: new Date().toISOString()
} }];
